head.script:
scwin.loginDTO = {};
scwin.loginClntNo = "";
scwin.loginClntNm = "";
scwin.userClsCd = "";
scwin.userId = "";
scwin.shpCo = "";
scwin.shpCoNm = "";
scwin.lineCd = "";
scwin.lineNm = "";
scwin.bookingNo = "";
scwin.orderCopy = "";

scwin.statusFlag = "";
scwin.line_logon = "";

// 화면 로딩 시
scwin.onpageload = function () {
    scwin.loginDTO = $c.data.getMemInfo();
    scwin.loginClntNo = scwin.loginDTO.clntNo || "";
    scwin.loginClntNm = scwin.loginDTO.clntNm || "";
    scwin.userClsCd = scwin.loginDTO.userClsCd || "";
    scwin.userId = scwin.loginDTO.userId || "";

    let paramData = $c.data.getParameter();

    scwin.shpCo = paramData.shpCo || "";
    scwin.shpCoNm = paramData.shpCoNm || "";
    scwin.lineCd = paramData.lineCd || "";
    scwin.lineNm = paramData.lineNm || "";
    scwin.bookingNo = paramData.bookingNo || "";
    scwin.orderCopy = paramData.copy || "";

    // 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정 tslines portcapt
    if (scwin.userId == "tslines") {
        scwin.line_logon = "TSL";
    }
};

scwin.onUdcCompleted = async function () {
    scwin.f_RetrieveGridLookup();

    if (scwin.userClsCd != "01") {  //사용자가 그룹사가 아닐때
        ed_shpCo.setValue(scwin.loginClntNo);
        txt_shpCoNm.setValue(scwin.loginClntNm);
        ed_shpCo.setReadOnly(true);
        txt_shpCoNm.setDisabled(true);

        $c.gus.cfDisableObjects([img_PopUp1]);

        await scwin.f_setLine();
        lc_cndLineCd.focus();
    } else {
        await scwin.f_setLine();
    }

    // EDI오더현황조회 화면에서 넘어오는 경우 처리
    if (scwin.lineCd != "" && scwin.bookingNo.trim() != "") {
        lc_cndLineCd.setValue(scwin.lineCd);
        ed_cndBookingNo.setValue(scwin.bookingNo);
        ed_shpCo.setValue(scwin.shpCo);
        txt_shpCoNm.setValue(scwin.shpCoNm);

        await scwin.f_setLineInfo(scwin.lineCd);
        await scwin.f_Retrieve();
    } else {
        scwin.f_Set("INIT");
        await scwin.f_setLine();
        scwin.f_setLineInfo();
    }

    if (scwin.line_logon == "TSL") {
        ds_bookingInfo.setCellData(0, "lineCd", scwin.line_logon);
        lc_cndLineCd.setValue("TSL");
        lc_selfYn.setValue("1");

        $c.gus.cfDisableObjects([ed_closeDt, ed_closeHh, txt_doorWrkPlNm, txt_arvWrkPlNm, txt_shpCoPicNm, txt_doorPicNm, txt_doorPicTelNo, txt_transCoPicNm, txt_transCoTelNo]);
    }

    scwin.f_setThatLine();

    // HSD라인의 경우 당사오더가 진행되면 수정하지 못하도록함
    let rowJson = ds_bookingInfo.getRowJSON(0);

    if (rowJson.lineCd == "HSD" && rowJson.mcomOdrNo != "") {
        $c.gus.cfDisableObjects([btn_update]);
    } else {
        if (scwin.orderCopy != "1") {
            $c.gus.cfEnableObjects([btn_update]);
        }
    }
};

scwin.f_setThatLine = function () {
    // SITC에서 접근하였을때 필수입력항목 및 타이틀 변경
    // 조건 : ID가 sitc0003 이며, 선사코드가 104911 인 경우
    if (scwin.userId == "sitc0003" && ed_shpCo.getValue() == "104911") {
        lc_cndLineCd.setValue("SITC");
        lc_lineCd.setValue("SITC");

        scwin.f_mandatoryChange();
        scwin.f_titleChange();
        scwin.f_hideControl();
        scwin.f_titleHide();
    } else if (scwin.userId == "portcapt" && ed_shpCo.getValue() == "100036") {
        lc_cndLineCd.setValue("GBH");
        lc_lineCd.setValue("GBH");

        scwin.f_mandatoryChange();
        scwin.f_titleChange();
        scwin.f_hideControl();
        scwin.f_titleHide();
    } else if (scwin.userId == "HSDLINE" && ed_shpCo.getValue() == "124845") {
        lc_cndLineCd.setValue("HSD");
        lc_lineCd.setValue("HSD");

        scwin.f_mandatoryChange();
        scwin.f_titleChange();
        scwin.f_hideControl();
        scwin.f_titleHide();
    } else if (ed_shpCo.getValue() == "225604" || ed_shpCo.getValue() == "133543" || ed_shpCo.getValue() == "112860" || ed_shpCo.getValue() == "112858") {
        lc_cndLineCd.setValue("SWIL");
        lc_lineCd.setValue("SWIL");
        ed_shippingPortCd.setValue("PUS");
        txt_shippingPortNm.setValue("BUSAN");
    }
};

// 필수항목을 제외한 나머지 컨트롤 hide
scwin.f_hideControl = function () {
    ed_closeDt.hide();
    img_closeDt.hide();
    ed_closeHh.hide();
    txt_dptWrkPlNm.hide();
    txt_doorPicNm.hide();
    txt_doorPicTelNo.hide();
    txt_arvWrkPlNm.hide();
    txt_shpCoPicNm.hide();
    txt_reqPicNm.hide();
    txt_reqPicTelNo.hide();
    lc_selfYn.hide();
    txt_transCoPicNm.hide();
    txt_transCoTelNo.hide();
    ed_rcvDt.hide();
    ed_rcvHh.hide();
    txt_confirmPicNm.hide();
    ed_confirmDt.hide();
    ed_confirmHh.hide();
    ed_mcomOdrNo.hide();
};

// 타이틀 hidden
scwin.f_titleHide = function () {
    tdClose.hide();
    tdDptWrkPl.hide();
    tdDoorPic.hide();
    tdArvWrkPl.hide();
    tdShpCoPic.hide();
    tdReqPic.hide();
    tdSelfYn.hide();
    tdTransCoPic.hide();
    tdRcvDt.hide();
    tdConfirmPic.hide();
    tdMcomOderNo.hide();
};

// 필수항목/타이틀 변경
scwin.f_mandatoryChange = function () {
    // Closing Time
    ed_closeDt.setMandatory(false);
    ed_closeHh.setMandatory(false);
    tdClose.removeClass("req");
    $c.gus.setValidExp(ed_closeDt, `Closing Time:no:date=YYYYMMDD`);
    $c.gus.setValidExp(ed_closeHh, `Closing Time:no:date=HHmm`);

    // 선적항구
    txt_shippingPortNm.setMandatory(false);
    led_shippingPortCd.removeClass("req");
    $c.gus.setValidExp(txt_shippingPortNm, `선적항구:no:maxByteLength=50`);

    // 출발작업장
    txt_dptWrkPlNm.setMandatory(false);
    tdDptWrkPl.removeClass("req");
    $c.gus.setValidExp(txt_dptWrkPlNm, `출발작업장:no:maxByteLength=50`);

    // Door작업장
    txt_doorWrkPlNm.setMandatory(false);
    tdDoor.removeClass("req");
    $c.gus.setValidExp(txt_doorWrkPlNm, `실화주:no:maxByteLength=50`);

    // 도착작업장
    txt_arvWrkPlNm.setMandatory(false);
    tdArvWrkPl.removeClass("req");
    $c.gus.setValidExp(txt_arvWrkPlNm, `도착작업장:no:maxByteLength=50`);

    // Door담당자
    txt_doorPicNm.setMandatory(false);
    txt_doorPicTelNo.setMandatory(false);
    tdDoorPic.removeClass("req");
    $c.gus.setValidExp(txt_doorPicNm, `Door담당자:no:maxByteLength=20`);
    $c.gus.setValidExp(txt_doorPicTelNo, `Door담당자 전화번호:no:maxByteLength=20`);

    // 선사담당자
    txt_shpCoPicNm.setMandatory(false);
    tdShpCoPic.removeClass("req");
    $c.gus.setValidExp(txt_shpCoPicNm, `선사담당자:no:maxByteLength=20`);

    // 자가
    lc_selfYn.setMandatory(false);
    tdSelfYn.removeClass("req");

    // 요청화주
    txt_reqMchtNm.setMandatory(true);
    tbReqMchtNm.addClass("req");
    $c.gus.setValidExp(txt_reqMchtNm, `화주명:yes:maxByteLength=50`);

    // 요청담당자
    $c.gus.setValidExp(txt_reqPicNm, `요청담당자:no:maxByteLength=20`);
    $c.gus.setValidExp(txt_reqPicTelNo, `요청담당자 전화번호:no:maxByteLength=20`);

    // 운송업체
    txt_transCoNm.setMandatory(true);
    ltxt_transCoNm.addClass("req");
    $c.gus.setValidExp(txt_transCoNm, `운송업체:yes:maxByteLength=30`);

    // 운송업체담당자
    $c.gus.setValidExp(txt_transCoPicNm, `운송업체담당자:no:maxByteLength=20`);
    $c.gus.setValidExp(txt_transCoTelNo, `운송업체담당자 전화번호:no:maxByteLength=20`);
};

// 타이틀 변경
scwin.f_titleChange = function () {
    tdDoor.setValue("실화주");
    tbReqMchtNm.setValue("화주명");
};

scwin.f_Set = function (gubun) {
    let rowJson = ds_bookingInfo.getRowJSON(0);

    switch (gubun) {
        case "INIT": // 초기화/신규
            ds_bookingInfo.setJSON([]);
            let row = ds_bookingInfo.insertRow();
            ds_bookingInfo.setRowPosition(row);

            if (ds_commInfo.getRowCount() > 0) {
                ds_commInfo.setJSON([]);
            }

            $c.gus.cfDisableBtnOnly([btn_update, btn_delete]);
            $c.gus.cfDisableKey();
            $c.gus.cfEnableBtnOnly([btn_create, btn_save, btn_addRow, btn_deleteRow, btn_undoRow]);
            $c.gus.cfInitObjects(tbl_infoArea);
            $c.gus.cfInitHidVal([tbl_infoArea]);

            gr_commInfo.setGridReadOnly(false);

            lc_cndLineCd.setValue("SWIL");
            lc_lineCd.setValue("SWIL");
            lc_lineCd.focus();

            scwin.statusFlag = "R";

            $c.gus.cfEnableObjects([ed_closeDt, ed_closeHh, ed_pickupDt, ed_pickuphh]);

            break;
        case "RETRIEVE": // 조회모드		  	
            $c.gus.cfDisableObjects(tbl_infoArea);
            $c.gus.cfDisableBtnOnly([btn_delete, btn_save, btn_addRow, btn_deleteRow, btn_undoRow]);
            $c.gus.cfEnableBtnOnly([btn_create]);

            // HSD라인의 경우 당사오더가 진행되면 수정하지 못하도록함
            if (rowJson.lineCd == "HSD" && rowJson.mcomOdrNo != "") {
                $c.gus.cfDisableObjects([btn_update]);
            } else {
                $c.gus.cfEnableObjects([btn_update]);
            }

            gr_commInfo.setGridReadOnly(true);

            if (rowJson.lineCd == "TSL") {
                if (rowJson.startPointStnClsCd == "S") {
                    ds_bookingInfo.setCellData(0, "dptWrkPlNm", "SEL");
                } else if (rowJson.startPointStnClsCd == "P") {
                    ds_bookingInfo.setCellData(0, "dptWrkPlNm", "PUS");
                }
            }

            break;
        case "UPDATE": // 수정모드         	  	
            $c.gus.cfDisableObjects(ed_bookingNo);
            $c.gus.cfEnableObjects(tbl_infoArea);
            $c.gus.cfDisableKey();
            $c.gus.cfEnableBtnOnly([btn_create, btn_save, btn_addRow, btn_deleteRow, btn_undoRow]);

            gr_commInfo.setGridReadOnly(false);

            scwin.statusFlag = "U";

            $c.gus.cfEnableObjects([ed_closeDt, ed_closeHh, ed_pickupDt, ed_pickuphh]);

            // 당사오더번호가 있는 경우, 삭제버튼 disable
            if (ds_bookingInfo.getRowCount() > 0 && !$c.gus.cfIsNull(rowJson.mcomOdrNo)) {
                $c.gus.cfDisableBtnOnly([btn_delete]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_delete]);
            }

            // 추가
            txt_transCoTelNo.setMandatory(false);
            $c.gus.setValidExp(txt_transCoTelNo, `운송업체담당자 전화번호:no:maxByteLength=20`);

            break;
        case "COPY": // 복사모드
            $c.gus.cfDisableKey();
            $c.gus.cfDisableBtnOnly([btn_update, btn_delete]);
            $c.gus.cfEnableBtnOnly([btn_create, btn_save, btn_addRow, btn_deleteRow, btn_undoRow]);

            // 오더번호는 운송 담당자가 새로운 번호로 오더 따기
            ds_bookingInfo.setCellData(0, "mcomOdrNo", "");
            // 240607) booking정보 오기입을 막기 위한 모선명, 항차, closing time, pickup일시 복사 제외
            ds_bookingInfo.setCellData(0, "vsslCd", "");
            ds_bookingInfo.setCellData(0, "vsslNm", "");
            ds_bookingInfo.setCellData(0, "portcnt", "");
            ds_bookingInfo.setCellData(0, "closeDt", "");
            ds_bookingInfo.setCellData(0, "closeHh", "");
            ds_bookingInfo.setCellData(0, "pickupdt", "");
            ds_bookingInfo.setCellData(0, "pickuphh", "");
            ds_bookingInfo.setCellData(0, "bookingNo", "");

            gr_commInfo.setGridReadOnly(false);

            ds_commInfo.modifyAllStatus("C");

            scwin.statusFlag = "R";
            $c.gus.cfEnableObjects([ed_closeDt, ed_closeHh, ed_pickupDt, ed_pickuphh]);

            break;
    }
};

scwin.f_FieldClear = async function (e) {
    if (scwin.userClsCd != "01") {
        $c.gus.cfInitObjects(tbl_cndArea);

        ed_shpCo.setValue(scwin.loginClntNo);
        txt_shpCoNm.setValue(scwin.loginClntNm);

        lc_cndLineCd.focus();
    } else {
        $c.gus.cfInitObjects(tbl_cndArea);
    }

    await scwin.f_setLine();

    if (scwin.statusFlag == "R") scwin.f_setLineInfo();
};

// Booking품명목록에서 Size,Type가져오기
scwin.f_RetrieveGridLookup = async function () {
    // 컨테이너 SIZE
    let sbm_cntrSize = {};
    sbm_cntrSize.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP101";

    let e = await $c.sbm.executeDynamic(sbm_cntrSize);

    ds_cntrSize.setJSON(e.responseJSON.GAUCE);

    // 컨테이너 TYPE
    let sbm_cntrType = {};
    sbm_cntrType.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP102";

    e = await $c.sbm.executeDynamic(sbm_cntrType);

    ds_cntrType.setJSON(e.responseJSON.GAUCE);
};

// 조회 
scwin.f_Retrieve = async function (e) {
    let chk = await $c.gus.cfValidate([tbl_cndArea], null, true);

    if (chk) {
        $c.sbm.execute(sbm_retrieve);
    }
};

// 저장
scwin.f_Save = async function () {
    let rowJson = ds_bookingInfo.getRowJSON(0);

    if (rowJson.printYn == "") {
        ds_bookingInfo.setCellData(0, "printYn", "0");
    }

    if (lc_cndLineCd.getValue() == "WW") {
        $c.gus.setValidExp(txt_arvWrkPlNm, `도착작업장:no:maxByteLength=50`);
        txt_arvWrkPlNm.setMandatory(false);
        tdArvWrkPl.removeClass("req");
    }

    if (lc_lineCd.getValue() == "TSL") {
        $c.gus.setValidExp(txt_transCoPicNm, `운송업체담당자:no:maxByteLength=20`);
        $c.gus.setValidExp(txt_transCoTelNo, `운송업체담당자 전화번호:no:maxByteLength=20`);
    }

    if (scwin.statusFlag == "U") {
        if (ds_bookingInfo.getModifiedIndex().length > 0 || ds_commInfo.getModifiedIndex().length > 0) {
            if (ds_commInfo.getRowCount() == ds_commInfo.getRowIndexByStatus("D").length) {
                await $c.win.alert("Booking품명정보이(가) 존재하지 않습니다.");
                return;
            }

            let chk1 = await $c.gus.cfValidate([tbl_infoArea, gr_commInfo], null, true);

            if (chk1) {
                let chk2 = await scwin.f_Validate();

                if (chk2) {
                    scwin.f_BeforeSave();

                    let msg = await $c.win.confirm(MSG_CM_CRM_001);

                    if (msg) {
                        $c.sbm.execute(sbm_update);
                    }
                }
            }
        } else {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Booking오더정보"]);
        }
    } else if (scwin.statusFlag == "R") {
        if (ds_bookingInfo.getModifiedIndex().length > 0 || ds_commInfo.getModifiedIndex().length > 0) {
            let chk1 = await $c.gus.cfValidate([tbl_infoArea, gr_commInfo], null, true);

            if (chk1) {
                let chk2 = await scwin.f_Validate();

                if (chk2) {
                    scwin.f_BeforeSave();

                    let msg = await $c.win.confirm(MSG_CM_CRM_001);

                    if (msg) {
                        $c.sbm.execute(sbm_save);
                    }
                }
            }
        } else {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Booking오더정보"]);
        }
    }
};

// 저장하기전에 값세팅
scwin.f_BeforeSave = function () {
    let bookingNo = ds_bookingInfo.getCellData(0, "bookingNo");
    ds_bookingInfo.setCellData(0, "bookingNo", bookingNo.replace("/[\s\u3000]+/g", ""));

    let rowJson = ds_bookingInfo.getRowJSON(0);

    if (ds_bookingInfo.getRowStatus(0) == "C") {
        ds_bookingInfo.setCellData(0, "ediYn", 0);

        for (let i = 0; i < ds_commInfo.getRowCount(); i++) {
            if (ds_commInfo.getRowStatus(i) == "C") {
                ds_commInfo.setCellData(i, "lineCd", rowJson.lineCd);
                ds_commInfo.setCellData(i, "bookingNo", rowJson.bookingNo);
            }
        }
    } else {
        for (let i = 0; i < ds_commInfo.getRowCount(); i++) {
            if (ds_commInfo.getRowStatus(i) == "C" || ds_commInfo.getRowStatus(i) == "U") {
                ds_commInfo.setCellData(i, "lineCd", rowJson.lineCd);
                ds_commInfo.setCellData(i, "bookingNo", rowJson.bookingNo);
            }
        }
    }

    if (rowJson.lineCd == "TSL") {
        if (rowJson.dptWrkPlNm == "SEL") {
            ds_bookingInfo.setCellData(0, "startPointStnClsCd", "S");
        } else if (rowJson.dptWrkPlNm == "PUS") {
            ds_bookingInfo.setCellData(0, "startPointStnClsCd", "P");
        }
    }
};

// 수정
scwin.f_Update = function (e) {
    scwin.f_Set("UPDATE");

    if (scwin.userId == "tslines") {
        scwin.line_logon = "TSL";

        ds_bookingInfo.setCellData(0, "lineCd", scwin.line_logon);
        lc_cndLineCd.setValue("TSL");
        lc_selfYn.setValue("1");

        $c.gus.cfDisableObjects([ed_closeDt, ed_closeHh, txt_doorWrkPlNm, txt_arvWrkPlNm, txt_shpCoPicNm, txt_doorPicNm, txt_doorPicTelNo, txt_transCoPicNm, txt_transCoTelNo]);
    }
};

// 신규 
scwin.f_Create = async function (e) {
    scwin.f_Set("INIT"); //신규모드
    await scwin.f_setLine();
    scwin.f_setLineInfo();

    if (scwin.userId == "tslines") {
        scwin.line_logon = "TSL";

        ds_bookingInfo.setCellData(0, "lineCd", scwin.line_logon);
        lc_cndLineCd.setValue("TSL");
        lc_selfYn.setValue("1");

        $c.gus.cfDisableObjects([ed_closeDt, ed_closeHh, txt_doorWrkPlNm, txt_arvWrkPlNm, txt_shpCoPicNm, txt_doorPicNm, txt_doorPicTelNo, txt_transCoPicNm, txt_transCoTelNo]);
    }
};

// 삭제
scwin.f_Delete = async function () {
    let rowJson = ds_bookingInfo.getRowJSON(0);

    let msg = await $c.win.confirm("Booking번호 : " + rowJson.bookingNo.trim() + "을(를) 삭제하시겠습니까?");

    if (msg) {
        if (ds_deleteCndInfo.getRowCount() > 0) ds_deleteCndInfo.setJSON([]);

        ds_deleteCndInfo.insertRow();
        ds_deleteCndInfo.setCellData(0, "lineCd", rowJson.lineCd.trim());
        ds_deleteCndInfo.setCellData(0, "bookingNo", rowJson.bookingNo.trim());

        $c.sbm.execute(sbm_delete);
    }
};

// 행추가
scwin.f_AddRow = function () {
    let row = ds_commInfo.insertRow();
    ds_commInfo.setRowPosition(row);

    gr_commInfo.setFocusedCell(row, "cntrSizCd");

    gr_commInfo.setColumnReadOnly("overLength", true);
    gr_commInfo.setColumnReadOnly("overHeight", true);
    gr_commInfo.setColumnReadOnly("overWidth", true);
};

// 행삭제
scwin.f_DeleteRow = function () {
    let row = ds_commInfo.getRowPosition();

    ds_commInfo.getRowStatus(row) == "C" ? ds_commInfo.removeRow(row) : ds_commInfo.deleteRow(row);
};

// 행취소
scwin.f_UndoRow = function () {
    if (!$c.gus.cfIsNull(ds_commInfo.getRowPosition())) {
        $c.data.undoRow(ds_commInfo, false);
    }
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함
scwin.f_ChkOpenCommonPopUp = function (gubun, data, isCode) {
    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_OpenCommonPopUp(gubun, data, "", "T", "T");
    } else { // inObj가 코드명 필드일 경우 팝업
        scwin.f_OpenCommonPopUp(gubun, "", data, "T", "T");
    }
};

// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다
scwin.f_OpenCommonPopUp = function (gubun, pCode, pName, pClose, pAllSearch) {
    switch (gubun) {
        case 2:
            // 선사 팝업
            udc_comCode.cfCommonPopUp(async function (rtnList) {
                $c.gus.cfSetReturnValue(rtnList, ed_shpCo, txt_shpCoNm);
                await scwin.f_setLine();
                if (scwin.statusFlag == "R") scwin.f_setLineInfo(); // 신규인 경우에만 라인콤보(조회데이터) 다시 조회
            }
                , pCode                  // 화면에서의 ??? Code Element의    Value
                , pName                  // 화면에서의 ??? Name Element의    Value
                , pClose                 // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서    
                , null                   // 보여주는 각 컬럼들의 폭  
                , null                   // 컬럼중에서 숨기는    컬럼 지정   
                , "SHP"                  // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의    사용자 정의 폭
                , null                   // POP-UP뛰을때 우도우의    사용자 정의 높이    
                , null                   // 윈도우 위치 Y좌표    
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부 ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "선사,선사코드,선사명"             // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
};

// 유효성체크
scwin.f_Validate = async function () {
    let rowJson = ds_bookingInfo.getRowJSON(0);

    // Door담당자 전화번호
    if (!(rowJson.lineCd == "TSL" || rowJson.lineCd == "SITC" || rowJson.lineCd == "HSD")) {
        let chk;

        if (txt_doorPicTelNo.getValue() != "") {
            chk = await scwin.phoneCheck(txt_doorPicTelNo.getValue());
            $c.data.p

            if (!chk) {
                return false;
            }
        }

        // 요청담당자 전화번호
        if (txt_reqPicTelNo.getValue() != "") {
            chk = await scwin.phoneCheck(txt_reqPicTelNo.getValue());

            if (!chk) {
                return false;
            }
        }

        // 운송업체담당자 전화번호
        if (txt_transCoTelNo.getValue() != "") {
            chk = await scwin.phoneCheck(txt_transCoTelNo.getValue());

            if (!chk) {
                return false;
            }
        }
    }

    // 품명정보 1건이상이어야 함.
    if (ds_commInfo.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["Booking품명정보"]);
        return false;
    }

    // 품명 정보 유효성 체크
    for (let i = 0; i < ds_commInfo.getRowCount(); i++) {
        let dcRowJson = ds_commInfo.getRowJSON(i);

        // 품명, SIZE 둘중 하나는 반드시 입력해야 함. 
        if ($c.gus.cfIsNull(dcRowJson.commNm) && $c.gus.cfIsNull(dcRowJson.cntrSizCd)) {
            await $c.gus.cfAlertMsg("품명 또는 SIZE 를 입력하여야 합니다.");

            ds_commInfo.setRowPosition(i);
            gr_commInfo.setFocusedCell(i, "commNm");
            return false;
        }

        // 품명을 입력하면 수량, 중량,CBM중 하나는 필수
        if (!$c.gus.cfIsNull(dcRowJson.commNm)) {
            // 수량, 중량, CBM 중 한가지는 입력하여야 합니다.
            if (dcRowJson.qty == 0 && dcRowJson.wt == 0 && dcRowJson.cbm == 0) {
                await $c.gus.cfAlertMsg("수량, 중량, CBM 중 한가지는 입력하셔야 합니다.");

                ds_commInfo.setRowPosition(i);
                gr_commInfo.setFocusedCell(i, "qty");
                return false;
            }
        }

        // SIZE 를 선택하면 수량은 필수
        if (!$c.gus.cfIsNull(dcRowJson.cntrSizCd) && $c.num.parseInt(dcRowJson.qty, 0) <= 0) {
            if ($c.num.parseInt(dcRowJson.qty, 0) == 0) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["수량"]);
            } else if ($c.num.parseInt(dcRowJson.qty, 0) < 0) {
                await $c.win.alert("수량은 1 이상의 값을 입력해주세요.");
            }

            ds_commInfo.setRowPosition(i);
            gr_commInfo.setFocusedCell(i, "qty");
            return false;
        }

        // 컨테이너 type RF가 아니면 온도는 0 이상
        if (dcRowJson.cntrTypCd != "RF" && dcRowJson.temper < 0) {
            await $c.gus.cfAlertMsg("컨테이너 " + dcRowJson.cntrTypCd + "의 온도는 0 이상으로 입력해주세요.");

            ds_commInfo.setRowPosition(i);
            gr_commInfo.setFocusedCell(i, "temper");
            return false;
        }
    }

    return true;
};

//-------------------------------------------------------------------------
// 라인콤보 조회 
//-------------------------------------------------------------------------
scwin.f_setLine = async function () {
    let sbm_LineList = {};
    sbm_LineList.action = "/cm.zz.RetrieveComboCMD.do?sysCd=LineEBC&queryId=retrieveLineEachShpCoCdCombo"
        + "&param1=" + scwin.loginClntNo
        + "&param2=" + scwin.userClsCd
        + "&param3=" + ed_shpCo.getValue();

    let e = await $c.sbm.executeDynamic(sbm_LineList);

    ds_LineList.setJSON(e.responseJSON.GAUCE);

    lc_cndLineCd.setSelectedIndex(0);

    // MSC 라인일때 - 2017.11.23 서동원 추가 
    if (scwin.userId == "dwstms") {
        ds_LineList.setJSON([]);
        ds_LineListInfo.setJSON([]);

        ds_LineList.insertRow();
        ds_LineListInfo.insertRow();

        ds_LineList.setCellData(0, "code", "TMSC");
        ds_LineListInfo.setCellData(0, "code", "TMSC");

        ds_LineList.setCellData(0, "name", "DOOWOO SHIPPING CO.,LTD");
        ds_LineListInfo.setCellData(0, "code", "TMSC");
    }
};

//-------------------------------------------------------------------------
// 조회 후, 라인콤보 조회 
//-------------------------------------------------------------------------
scwin.f_setLineInfo = async function (beforeLineCd) {
    let sbm_LineListInfo = {};
    sbm_LineListInfo.action = "/cm.zz.RetrieveComboCMD.do?sysCd=LineEBC&queryId=retrieveLineEachShpCoCdCombo"
        + "&param1=" + scwin.loginClntNo
        + "&param2=" + scwin.userClsCd
        + "&param3=" + ed_shpCo.getValue();

    let e = await $c.sbm.executeDynamic(sbm_LineListInfo);

    ds_LineListInfo.setJSON(e.responseJSON.GAUCE);

    if (ds_bookingInfo.getRowCount() > 0) {
        lc_lineCd.setValue(ds_bookingInfo.getCellData(0, "lineCd"));

        // MSC 라인일때 - 2017.11.23 서동원 추가 
        if (scwin.userId == "dwstms") {
            ds_LineList.setJSON([]);
            ds_LineListInfo.setJSON([]);

            ds_LineList.insertRow();
            ds_LineListInfo.insertRow();

            ds_LineList.setCellData(0, "code", "TMSC");
            ds_LineListInfo.setCellData(0, "code", "TMSC");

            ds_LineList.setCellData(0, "name", "DOOWOO SHIPPING CO.,LTD");
            ds_LineListInfo.setCellData(0, "code", "TMSC");
        }
    }

    if (beforeLineCd != null && beforeLineCd != "") {
        lc_cndLineCd.setValue(beforeLineCd);
        lc_lineCd.setValue(beforeLineCd);
    } else {
        lc_cndLineCd.setSelectedIndex(-1);
        lc_lineCd.setSelectedIndex(-1);
    }
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    let cnt = ds_commInfo.getRowCount();

    if (ds_bookingInfo.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003, ["조회결과"]);

        let beforeLineCd = lc_cndLineCd.getValue();

        await scwin.f_Set("RETRIEVE");
        await scwin.f_setLine();
        scwin.f_setLineInfo(beforeLineCd);
    } else {
        // HSD라인의 경우 당사오더가 진행되면 수정하지 못하도록함
        let rowJson = ds_bookingInfo.getRowJSON(0);

        lc_lineCd.setValue(rowJson.lineCd);

        if (rowJson.lineCd == "HSD" && rowJson.mcomOdrNo != "") {
            $c.gus.cfDisableObjects([btn_update]);
        } else {
            $c.gus.cfEnableObjects([btn_update]);
        }

        await scwin.f_Set("RETRIEVE");

        ds_bookingInfo.setRowPosition(0);

    }

    // 복사여부가 1일때 lineCd와 bookingNo으로 조회한 정보에 대해 복사모드로 세팅
    if (scwin.orderCopy == "1") {
        scwin.f_Set("COPY");

        // bookingNo만 빈값으로 세팅
        ed_cndBookingNo.setValue("");
        ds_bookingInfo.setCellData(0, "bookingNo", "");

        scwin.orderCopy = "0";
    }

    totalRows.setValue(cnt);

    ed_cndBookingNo.focus();
};

scwin.sbm_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    lc_cndLineCd.setSelectedIndex(lc_lineCd.getSelectedIndex());
    ed_cndBookingNo.setValue(ed_bookingNo.getValue());

    scwin.f_Retrieve();
};

scwin.sbm_update_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    lc_cndLineCd.setSelectedIndex(lc_lineCd.getSelectedIndex());
    ed_cndBookingNo.setValue(ed_bookingNo.getValue());

    scwin.f_Retrieve();
};

scwin.sbm_delete_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.gus.cfAlertMsg(MSG_CM_INF_004);

    scwin.f_Set("INIT");
    scwin.f_FieldClear();

    if (scwin.userId == "tslines") {
        scwin.line_logon = "TSL";

        ds_bookingInfo.setCellData(0, "lineCd", scwin.line_logon);
        lc_cndLineCd.setValue("TSL");
        lc_selfYn.setValue("1");

        $c.gus.cfDisableObjects([ed_closeDt, ed_closeHh, txt_doorWrkPlNm, txt_arvWrkPlNm, txt_shpCoPicNm, txt_doorPicNm, txt_doorPicTelNo, txt_transCoPicNm, txt_transCoTelNo]);
    }
};

scwin.udc_comCode_onblurCodeEvent = async function (e) {
    if (ed_shpCo.originalValue == ed_shpCo.getValue()) return;
    if (ed_shpCo.getValue() == "") {
